filename = input("Enter filename: ")
longest = ""
with open(filename, 'r') as f:
    for line in f:
        for word in line.split():
            if len(word) > len(longest):
                longest = word
print("Longest word:", longest)

def is_palindrome(s):
    if len(s) < 2:
        return True
    if s[0] != s[-1]:
        return False
    return is_palindrome(s[1:-1])
word = input("Enter a word: ")
if is_palindrome(word):
    print("Palindrome")
else:
    print("Not a palindrome")

def c_to_f(c):
    return (c * 9/5) + 32
def f_to_c(f):
    return (f - 32) * 5/9
choice = input("Convert (C) to F or (F) to C? ").upper()
val = float(input("Enter temperature: "))
if choice == "C":
    print(c_to_f(val), "F")
else:
    print(f_to_c(val), "C")

