def is_perfect(n):
    s = 0
    for i in range(1, n):
        if n % i == 0:
            s += i
    return s == n
num = int(input("Enter a number: "))
if is_perfect(num):
    print("Perfect number")
else:
    print("Not perfect")

text = input("Enter a sentence: ")
vowels = 0
consonants = 0
spaces = 0
for ch in text:
    if ch.lower() in "aeiou":
        vowels += 1
    elif ch == ' ':
        spaces += 1
    elif ch.isalpha():
        consonants += 1
print(f"Vowels={vowels}, Consonants={consonants}, Spaces={spaces}")

balance = 0
while True:
    cmd = input("Enter command (D=deposit, W=withdraw, B=balance, Q=quit): ").upper()
    if cmd == 'Q':
        break
    elif cmd == 'D':
        amt = float(input("Enter amount to deposit: "))
        balance += amt
    elif cmd == 'W':
        amt = float(input("Enter amount to withdraw: "))
        balance -= amt
    elif cmd == 'B':
        print("Balance=", balance)

nums_str = input("Enter numbers (comma-separated): ")
nums = [int(x) for x in nums_str.split(",")]
pass_num = 1
for i in range(len(nums)-1):
    swapped = False
    for j in range(len(nums)-1-i):
        if nums[j] > nums[j+1]:
            nums[j], nums[j+1] = nums[j+1], nums[j]
            swapped = True
    print(f"Pass {pass_num}: {nums}")
    pass_num += 1
    if not swapped:
        break

def normalize(s):
    return sorted(s.replace(" ", "").lower())
str1 = input("Enter first string: ")
str2 = input("Enter second string: ")
if normalize(str1) == normalize(str2):
    print("Anagrams")
else:
    print("Not anagrams")

def fib(n):
    if n <= 1:
        return n
    return fib(n-1) + fib(n-2)
terms = int(input("How many terms? "))
for i in range(terms):
    print(fib(i), end=" ")
